1555	// commitTrackerLocked is the body of CommitTracker without the lock
1556	// acquisition. Callers must hold withTrackerLock(projectRoot) before calling.
1557	// Used by Run() to fold tracker commit, checkpoint synthesis, and worktree
1558	// creation into a single critical section so concurrent workers do not race
1559	// on the parent's HEAD ref (regression: niflheim concurrent `ddx work` hit
1560	// "cannot lock ref 'HEAD'" between unlocked CommitTracker and SynthesizeCommit).
1561	func commitTrackerLocked(projectRoot string) error {
1562		trackerFile := filepath.Join(projectRoot, ".ddx", "beads.jsonl")
1563		info, err := os.Stat(trackerFile)
1564		if err != nil {
1565			if os.IsNotExist(err) {
1566				return nil
1567			}
1568			return fmt.Errorf("checking tracker file: %w", err)
1569		}
1570		if info.IsDir() {
1571			return nil
1572		}
1573	
1574		out, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--is-inside-work-tree").Output()
1575		if err != nil || strings.TrimSpace(string(out)) != "true" {
1576			return nil
1577		}
1578	
1579		msg := fmt.Sprintf("chore: update tracker (execute-bead %s)", time.Now().UTC().Format("20060102T150405"))
1580	
1581		// Re-check inside the lock: a sibling worker may have already
1582		// committed the tracker changes between our pre-lock check and now.
1583		diff, err := internalgit.Command(context.Background(), projectRoot, "diff", "--", ".ddx/beads.jsonl").Output()
1584		if err != nil {
1585			return fmt.Errorf("checking tracker diff: %w", err)
1586		}
1587		if strings.TrimSpace(string(diff)) == "" {
1588			untracked, err := internalgit.Command(context.Background(), projectRoot, "ls-files", "--others", "--exclude-standard", ".ddx/beads.jsonl").Output()
1589			if err != nil {
1590				return fmt.Errorf("checking tracker untracked: %w", err)
1591			}
1592			if strings.TrimSpace(string(untracked)) == "" {
1593				return nil
1594			}
1595		}
1596	
1597		commitOut, err := internalgit.Command(context.Background(), projectRoot, "add", ".ddx/beads.jsonl").CombinedOutput()
1598		if err != nil {
1599			return fmt.Errorf("staging tracker: %s: %w", strings.TrimSpace(string(commitOut)), err)
1600		}
1601		// `git commit` would fail with "nothing to commit" if the file's
1602		// content is byte-identical to HEAD even though `git diff` saw a
1603		// diff (e.g. mode/whitespace race). Bail cleanly in that case.
1604		if cached, err := internalgit.Command(context.Background(), projectRoot, "diff", "--cached", "--", ".ddx/beads.jsonl").Output(); err == nil && strings.TrimSpace(string(cached)) == "" {
1605			return nil
1606		}
1607		commitOut, err = internalgit.Command(context.Background(), projectRoot, "commit", "--no-verify", "--only", "-m", msg, "--", ".ddx/beads.jsonl").CombinedOutput()
1608		if err != nil {
1609			return fmt.Errorf("committing tracker: %s: %w", strings.TrimSpace(string(commitOut)), err)
1610		}
1611		return nil
1612	}
